final:
module johnson_counter (
    input clk,
    input rst_n,
    output reg [15:0] count
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge rst_n or posedge dbg_halt) begin
    if (!rst_n)
        count <= 16'b0000000000000000;
    else
        count <= {~count[0], count[15:1]};
end

endmodule
